import React from 'react';
import { TrendingUp, TrendingDown, Minus } from 'lucide-react';

export default function StatCard({ label, value, trend, trendLabel, icon: Icon, iconColor = 'brand', formatter }) {
  const displayValue = formatter ? formatter(value) : value;

  const iconColorMap = {
    brand: 'bg-brand-50 text-brand-600',
    teal: 'bg-brand-50 text-brand-600',
    amber: 'bg-accent-50 text-accent-600',
    green: 'bg-emerald-50 text-emerald-600',
    red: 'bg-red-50 text-red-600',
    blue: 'bg-blue-50 text-blue-600',
    // legacy aliases so existing callers don't break
    violet: 'bg-brand-50 text-brand-600',
    cyan: 'bg-brand-50 text-brand-600',
  };

  const trendPositive = trend > 0;
  const trendNeutral = trend === 0;

  return (
    <div className="stat-card hover:shadow-md transition-shadow duration-200">
      <div className="flex items-start justify-between mb-4">
        {Icon && (
          <div className={`w-10 h-10 rounded-lg flex items-center justify-center flex-shrink-0 ${iconColorMap[iconColor] || iconColorMap.brand}`}>
            <Icon size={20} />
          </div>
        )}
        {trend !== undefined && (
          <div
            className={`flex items-center gap-1 text-xs font-semibold px-2 py-1 rounded-full
              ${trendNeutral ? 'bg-slate-100 text-slate-500'
              : trendPositive ? 'bg-emerald-50 text-emerald-600'
              : 'bg-red-50 text-red-600'}`}
          >
            {trendNeutral ? (
              <Minus size={12} />
            ) : trendPositive ? (
              <TrendingUp size={12} />
            ) : (
              <TrendingDown size={12} />
            )}
            {trendNeutral ? 'No change' : `${trendPositive ? '+' : ''}${trend}${trendLabel || ''}`}
          </div>
        )}
      </div>

      <div className="mt-1">
        <p className="text-2xl font-bold font-display text-slate-900 leading-none">
          {displayValue}
        </p>
        <p className="text-sm text-slate-500 mt-1.5 font-medium">{label}</p>
      </div>
    </div>
  );
}
